import React, { useState } from 'react';
import { MapContainer, TileLayer, Polyline, Marker, Popup } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import api from '../services/api';

// Fix default marker icons
import markerIcon2x from 'leaflet/dist/images/marker-icon-2x.png';
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconUrl: markerIcon,
  iconRetinaUrl: markerIcon2x,
  shadowUrl: markerShadow,
});

const RouteOptimization = () => {
  const [start, setStart] = useState('');
  const [end, setEnd] = useState('');
  const [routeCoords, setRouteCoords] = useState([]);
  const [routeDetails, setRouteDetails] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Convert address to lat/lng using your backend API
  const geocode = async (location) => {
    const response = await api.get(`/geocode?address=${encodeURIComponent(location)}`);
    return response.data; // { lat, lng }
  };

  const handleOptimizeRoute = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setRouteCoords([]);
    setRouteDetails(null);

    try {
      const startCoords = await geocode(start);
      const endCoords = await geocode(end);

      // Call backend ORS/OSRM route optimization API
      const response = await api.post('/routes/optimize', {
        start: startCoords,
        end: endCoords,
      });

      // Example response: array of [lat, lng]
      setRouteCoords(response.data.coordinates);

      setRouteDetails({
        distance: response.data.distance, // km
        duration: response.data.duration, // seconds
        start: startCoords,
        end: endCoords,
      });
    } catch (err) {
      console.error(err);
      setError('Failed to optimize route. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const center = routeCoords.length
    ? routeCoords[0]
    : [20.5937, 78.9629]; // default India center

  return (
    <div className="space-y-6">
      <h2 className="g-title">Route Optimization</h2>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 stat-card">
          <h3 className="text-lg font-semibold mb-4">Route Map</h3>
          <MapContainer center={center} zoom={6} className="w-full h-[600px] rounded-lg shadow-md">
            <TileLayer
              attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a> contributors'
              url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            />
            {routeCoords.length > 0 && (
              <>
                <Polyline positions={routeCoords} color="blue" />
                <Marker position={routeCoords[0]}>
                  <Popup>Start: {start}</Popup>
                </Marker>
                <Marker position={routeCoords[routeCoords.length - 1]}>
                  <Popup>End: {end}</Popup>
                </Marker>
              </>
            )}
          </MapContainer>
        </div>

        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">Route Planner</h3>
          <form onSubmit={handleOptimizeRoute} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Start Location</label>
              <input
                type="text"
                className="g-input"
                placeholder="Enter start location"
                value={start}
                onChange={(e) => setStart(e.target.value)}
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">End Location</label>
              <input
                type="text"
                className="g-input"
                placeholder="Enter end location"
                value={end}
                onChange={(e) => setEnd(e.target.value)}
                required
              />
            </div>
            <button type="submit" className="g-btn" disabled={loading}>
              {loading ? 'Optimizing...' : 'Optimize Route'}
            </button>
            {error && <p className="g-error">{error}</p>}
          </form>

          {routeDetails && (
            <div className="mt-4">
              <h4 className="text-md font-semibold">Route Details</h4>
              <p>Distance: {routeDetails.distance.toFixed(2)} km</p>
              <p>Duration: {Math.floor(routeDetails.duration / 60)} min</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default RouteOptimization;
